#include <stdio.h>
#include <string.h>

int main() {
    int T;
    char S[1000001];

    scanf("%d", &T);
    while (T--) {
        scanf("%s", S);
        int i, n = strlen(S);

        for (i = 0; i < n / 2; i++) {
            if (S[i] != S[n - i - 1]) {
                printf("NO\n");
                goto next;
            }
        }
        printf("YES\n");
        next:
    }
    return 0;
}

