code.Java:
public class Main {
    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        sc.nextLine();

        while (T-- > 0) {
            String S = sc.nextLine();
            int n = S.length();

            for (int i = 0; i < n / 2; i++) {
                if (S.charAt(i) != S.charAt(n - i - 1)) {
                    System.out.println("NO");
                    continue;
                }
            }
            System.out.println("YES");
        }
    }
}

